<?php declare(strict_types=1);require __DIR__.'/bootstrap.php';$customer=vp3_require_customer();$orderId=(int)($_SESSION['last_order_id']??0);$order=null;if($orderId&&vp3_db_available()){$stmt=vp3_db()->prepare('SELECT order_number,order_status,payment_status,total_cents,currency FROM orders WHERE id=? AND customer_id=?');$stmt->execute([$orderId,$customer['id']]);$order=$stmt->fetch();} $pageTitle='Order Received';require VP3_ROOT.'/includes/header.php';?><section class="form-shell"><span class="eyebrow">Order received</span><h1>Your launch request is recorded.</h1><?php if($order):?><p>Order <strong><?=vp3_e($order['order_number'])?></strong> is currently <span class="badge <?=vp3_e($order['payment_status'])?>"><?=vp3_e($order['payment_status'])?></span>.</p><?php endif;?><p>A VP3 administrator can now confirm pricing, collect payment through the configured provider, issue a license, and create a hosting account when applicable.</p><a class="button" href="account-orders.php">View orders</a></section><?php require VP3_ROOT.'/includes/footer.php';?>